import { calculateCRC16 } from '@/utils/crc16';

export interface VietQRParseResult {
  isValid: boolean;
  isDynamic: boolean;
  isCard?: boolean; // True nếu thanh toán qua số thẻ (QRIBFTTC)
  beneficiary?: {
    bankBin: string;
    accountNo: string;
    accountName?: string;
  };
  transaction?: {
    amount?: number;
    content?: string;
  };
  rawTags?: Record<string, string>; // Chứa toàn bộ các tags chưa được map
  errorMessage?: string;
}

function parseTLV(data: string): Record<string, string> {
  const tags: Record<string, string> = {};
  let i = 0;
  while (i < data.length) {
    if (i + 4 > data.length) break;
    const tag = data.substring(i, i + 2);
    const length = parseInt(data.substring(i + 2, i + 4), 10);
    if (isNaN(length)) break;
    if (i + 4 + length > data.length) break;
    const value = data.substring(i + 4, i + 4 + length);
    tags[tag] = value;
    i += 4 + length;
  }
  return tags;
}

export function parseVietQR(qrString: string): VietQRParseResult {
  const defaultResult: VietQRParseResult = {
    isValid: false,
    isDynamic: false
  };

  if (!qrString || qrString.length < 4) {
    return { ...defaultResult, errorMessage: 'Invalid QR string length' };
  }

  // Extract CRC. Tag 63 is always at the end and has a fixed length of 04.
  // The CRC value itself is 4 characters. So Tag(2) + Length(2) + Value(4) = 8 characters.
  const crcTagIndex = qrString.length - 8;
  if (crcTagIndex < 0 || qrString.substring(crcTagIndex, crcTagIndex + 4) !== '6304') {
    return { ...defaultResult, errorMessage: 'Missing or invalid CRC tag' };
  }

  const payloadToCRC = qrString.substring(0, crcTagIndex + 4);
  const expectedCRC = calculateCRC16(payloadToCRC);
  const actualCRC = qrString.substring(crcTagIndex + 4).toUpperCase();

  if (expectedCRC !== actualCRC) {
    return { ...defaultResult, errorMessage: 'CRC checksum validation failed (Tampered QR)' };
  }

  const rootTags = parseTLV(qrString);
  
  // Validate Country Code and Currency
  if (rootTags['58'] && rootTags['58'] !== 'VN') {
    return { ...defaultResult, errorMessage: 'Unsupported Country Code. Only VN is supported.' };
  }
  if (rootTags['53'] && rootTags['53'] !== '704') {
    return { ...defaultResult, errorMessage: 'Unsupported Currency. Only VND (704) is supported.' };
  }

  // Tag 38 is mandatory for NAPAS 247
  if (!rootTags['38']) {
    return { ...defaultResult, errorMessage: 'Missing NAPAS Account Information (Tag 38)' };
  }

  const tag38 = parseTLV(rootTags['38']);
  if (!tag38['01']) {
    return { ...defaultResult, errorMessage: 'Missing Beneficiary Organization Information' };
  }
  
  const beneficiaryInfo = parseTLV(tag38['01']);
  const bankBin = beneficiaryInfo['00'] || '';
  const accountNo = beneficiaryInfo['01'] || '';

  if (!bankBin || !accountNo) {
    return { ...defaultResult, errorMessage: 'Missing Bank BIN or Account Number' };
  }

  const isDynamic = rootTags['01'] === '12';
  const isCard = tag38['02'] === 'QRIBFTTC';
  const amountStr = rootTags['54'];
  const amount = amountStr ? parseInt(amountStr, 10) : undefined;
  const accountName = rootTags['59'];
  
  let content: string | undefined = undefined;
  if (rootTags['62']) {
    const tag62 = parseTLV(rootTags['62']);
    content = tag62['08'];
  }

  return {
    isValid: true,
    isDynamic,
    isCard,
    beneficiary: {
      bankBin,
      accountNo,
      accountName: accountName === 'NA' ? undefined : accountName
    },
    transaction: {
      amount: (amount !== undefined && !isNaN(amount)) ? amount : undefined,
      content
    },
    rawTags: rootTags
  };
}
