import { generateVietQR, getBankByBin, getBankByCode, sanitizeAccountName } from '@viet-qr/core';
import QRCode from 'qrcode';

export class VietQRCompactCard extends HTMLElement {
  static get observedAttributes() {
    return [
      'bank-id',
      'account-no',
      'account-name',
      'amount',
      'content',
      'is-card',
      'size',
      'bank-logo',
      'theme'
    ];
  }

  private qrContainer: HTMLElement | null = null;
  private logoImg: HTMLImageElement | null = null;
  private bankNameH3: HTMLHeadingElement | null = null;
  private accountNameP: HTMLParagraphElement | null = null;
  private accountNoP: HTMLParagraphElement | null = null;
  private amountP: HTMLParagraphElement | null = null;

  constructor() {
    super();
  }

  connectedCallback() {
    this.renderInitial();
    this.updateData();
  }

  attributeChangedCallback() {
    this.updateData();
  }

  private renderInitial() {
    // Không dùng Shadow DOM để kế thừa trực tiếp CSS toàn cục (styles.css)
    const theme = this.getAttribute('theme') || 'light';
    
    this.innerHTML = `
      <div class="vqr-compact-card vqr-theme-${theme}" id="card-wrapper">
        <div class="vqr-compact-card__header">
          <img id="logo-img" class="vqr-compact-card__logo" style="display: none;" />
          <h3 id="bank-name-h3" class="vqr-compact-card__bank-name" style="display: none;"></h3>
        </div>

        <div class="vqr-compact-card__qr-wrapper" id="qr-container">
          <!-- QR Code SVG will be injected here -->
        </div>

        <div class="vqr-compact-card__info">
          <div class="vqr-compact-card__info-row" id="account-name-row" style="display: none;">
            <span class="vqr-compact-card__label">Tên tài khoản</span>
            <p class="vqr-compact-card__value" id="account-name-p"></p>
          </div>
          
          <div class="vqr-compact-card__info-row">
            <span class="vqr-compact-card__label">Số tài khoản</span>
            <p class="vqr-compact-card__value" id="account-no-p"></p>
          </div>

          <div class="vqr-compact-card__info-row" id="amount-row" style="margin-top: 16px; display: none;">
            <span class="vqr-compact-card__label">Thanh toán</span>
            <p class="vqr-compact-card__amount" id="amount-p"></p>
          </div>
        </div>
      </div>
    `;

    this.qrContainer = this.querySelector('#qr-container');
    this.logoImg = this.querySelector('#logo-img');
    this.bankNameH3 = this.querySelector('#bank-name-h3');
    this.accountNameP = this.querySelector('#account-name-p');
    this.accountNoP = this.querySelector('#account-no-p');
    this.amountP = this.querySelector('#amount-p');
  }

  private async updateData() {
    if (!this.qrContainer) return; // Not mounted yet

    const bankId = this.getAttribute('bank-id') || '';
    const accountNo = this.getAttribute('account-no') || '';
    const accountName = this.getAttribute('account-name') || '';
    const amountStr = this.getAttribute('amount');
    const amount = amountStr ? parseInt(amountStr, 10) : undefined;
    const content = this.getAttribute('content') || '';
    const isCard = this.getAttribute('is-card') === 'true';
    const size = parseInt(this.getAttribute('size') || '240', 10);
    const bankLogo = this.getAttribute('bank-logo');
    const theme = this.getAttribute('theme') || 'light';

    const wrapper = this.querySelector('#card-wrapper');
    if (wrapper) {
      wrapper.className = `vqr-compact-card vqr-theme-${theme}`;
    }

    // Update Header
    const bankInfo = getBankByBin(bankId) || getBankByCode(bankId);
    const bankName = bankInfo?.name || bankId;

    if (bankLogo && this.logoImg && this.bankNameH3) {
      this.logoImg.src = bankLogo;
      this.logoImg.alt = bankName;
      this.logoImg.style.display = 'block';
      this.bankNameH3.style.display = 'none';
    } else if (this.bankNameH3 && this.logoImg) {
      this.bankNameH3.textContent = bankName;
      this.bankNameH3.style.display = 'block';
      this.logoImg.style.display = 'none';
    }

    // Update Info
    if (this.accountNameP) {
      const row = this.querySelector('#account-name-row') as HTMLElement;
      if (accountName) {
        this.accountNameP.textContent = sanitizeAccountName(accountName);
        row.style.display = 'flex';
      } else {
        row.style.display = 'none';
      }
    }

    if (this.accountNoP) {
      this.accountNoP.textContent = accountNo;
    }

    if (this.amountP) {
      const row = this.querySelector('#amount-row') as HTMLElement;
      if (amount) {
        this.amountP.textContent = new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
        row.style.display = 'flex';
      } else {
        row.style.display = 'none';
      }
    }

    // Generate QR
    if (bankId && accountNo) {
      try {
        const payload = generateVietQR({ bankId, accountNo, accountName, amount, content, isCard });
        const svgString = await QRCode.toString(payload, {
          type: 'svg',
          width: size,
          margin: 1,
          color: {
            dark: '#000000',
            light: '#ffffff'
          }
        });
        this.qrContainer.innerHTML = svgString;
      } catch (err) {
        console.error('Failed to generate VietQR:', err);
        this.qrContainer.innerHTML = '<p style="color: red;">Invalid QR Data</p>';
      }
    }
  }
}
