import { banks as defaultBanks, Bank } from '@/constants/banks';

const binIndex: Record<string, Bank> = {};
const codeIndex: Record<string, Bank> = {};
const nameIndex: Record<string, Bank> = {};

/**
 * Cập nhật danh sách ngân hàng bộ nhớ.
 */
export function setBankList(banks: Bank[]): void {
  if (!Array.isArray(banks)) {
    throw new Error('Invalid bank list: must be an array');
  }
  
  // Clear existing
  for (const key of Object.keys(binIndex)) delete binIndex[key];
  for (const key of Object.keys(codeIndex)) delete codeIndex[key];
  for (const key of Object.keys(nameIndex)) delete nameIndex[key];

  for (const bank of banks) {
    if (!bank.bin || !bank.code || !bank.name) {
      throw new Error('Invalid bank format: must contain bin, code, and name');
    }
    binIndex[bank.bin] = bank;
    codeIndex[bank.code.toUpperCase()] = bank;
    nameIndex[bank.name.toUpperCase()] = bank;
  }
}

// Khởi tạo index ban đầu từ danh sách offline
setBankList(defaultBanks);

/**
 * Lấy thông tin ngân hàng qua mã BIN (O(1))
 */
export function getBankByBin(bin: string): Bank | undefined {
  return binIndex[bin];
}

/**
 * Lấy thông tin ngân hàng qua mã Code (O(1))
 */
export function getBankByCode(code: string): Bank | undefined {
  if (!code) return undefined;
  return codeIndex[code.toUpperCase()];
}

/**
 * Lấy thông tin ngân hàng qua tên (Note: shortName) (O(1))
 */
export function getBankByName(name: string): Bank | undefined {
  if (!name) return undefined;
  return nameIndex[name.toUpperCase()];
}

/**
 * Cập nhật danh sách ngân hàng từ một API hoặc CDN bất kỳ.
 * API/CDN trả về phải có cấu trúc giống hệt API v2/banks của vietqr.io (có mảng .data)
 * HOẶC là mảng JSON thuần tuân theo interface Bank[] của thư viện này.
 */
export async function fetchBankList(url: string): Promise<void> {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
    const json = await res.json();
    
    // Hỗ trợ mảng thuần (CDN) hoặc cấu trúc gốc vietqr.io (json.data)
    let bankData: any[] = [];
    if (Array.isArray(json)) {
      bankData = json;
    } else if (json.data && Array.isArray(json.data)) {
      bankData = json.data;
    } else {
      throw new Error('Invalid response format. Expected an array or an object with a "data" array.');
    }
    
    // Map dữ liệu về chuẩn Bank
    const mappedBanks: Bank[] = bankData.map(b => ({
      bin: b.bin,
      code: b.code,
      name: b.name,
      fullName: b.full_name,
      swiftCode: b.swift_code || ''
    }));
    
    setBankList(mappedBanks);
  } catch (error) {
    console.error('Failed to fetch bank list:', error);
    throw error;
  }
}
